import{_ as e,c as o,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Funcionalidades da Plataforma: Comandos Principais e Gerenciamento de Skills | OpenSkills","description":"Aprenda as funcionalidades da plataforma OpenSkills, domine operações principais como comandos, instalação, listagem, atualização e remoção de skills, entenda as diferenças entre gerenciamento global e por projeto.","frontmatter":{"title":"Funcionalidades da Plataforma: Comandos Principais e Gerenciamento de Skills | OpenSkills","sidebarTitle":"Dominar Operações Principais","subtitle":"Funcionalidades da Plataforma: Comandos Principais e Gerenciamento de Skills | OpenSkills","description":"Aprenda as funcionalidades da plataforma OpenSkills, domine operações principais como comandos, instalação, listagem, atualização e remoção de skills, entenda as diferenças entre gerenciamento global e por projeto.","order":2},"headers":[],"relativePath":"pt/numman-ali/openskills/platforms/index.md","filePath":"pt/numman-ali/openskills/platforms/index.md"}'),l={name:"pt/numman-ali/openskills/platforms/index.md"};function t(d,a,r,n,c,p){return s(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="funcionalidades-da-plataforma" tabindex="-1">Funcionalidades da Plataforma <a class="header-anchor" href="#funcionalidades-da-plataforma" aria-label="Permalink to &quot;Funcionalidades da Plataforma&quot;">​</a></h1><p>Este capítulo aprofunda os comandos principais do OpenSkills CLI e as funcionalidades de gerenciamento de skills, ajudando você a passar de &quot;saber usar&quot; para &quot;dominar&quot;.</p><h2 id="pre-requisitos" tabindex="-1">Pré-requisitos <a class="header-anchor" href="#pre-requisitos" aria-label="Permalink to &quot;Pré-requisitos&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Antes de Começar</p><p>Antes de estudar este capítulo, certifique-se de ter concluído o capítulo <a href="./../start/">Início Rápido</a>, especialmente:</p><ul><li><a href="./../start/installation/">Instalação do OpenSkills</a>: OpenSkills CLI instalado com sucesso</li><li><a href="./../start/first-skill/">Instalar sua Primeira Skill</a>: compreensão do fluxo básico de instalação de skills</li></ul></div><h2 id="conteudo-deste-capitulo" tabindex="-1">Conteúdo deste Capítulo <a class="header-anchor" href="#conteudo-deste-capitulo" aria-label="Permalink to &quot;Conteúdo deste Capítulo&quot;">​</a></h2><p>Este capítulo contém 6 tópicos cobrindo todas as funcionalidades principais do OpenSkills:</p><h3 id="detalhes-dos-comandos" tabindex="-1"><a href="./cli-commands/">Detalhes dos Comandos</a> <a class="header-anchor" href="#detalhes-dos-comandos" aria-label="Permalink to &quot;[Detalhes dos Comandos](./cli-commands/)&quot;">​</a></h3><p>Introdução completa aos 7 comandos, parâmetros e flags, com tabela de referência rápida. Ideal para usuários que precisam consultar rapidamente a sintaxe dos comandos.</p><h3 id="detalhes-das-fontes-de-instalacao" tabindex="-1"><a href="./install-sources/">Detalhes das Fontes de Instalação</a> <a class="header-anchor" href="#detalhes-das-fontes-de-instalacao" aria-label="Permalink to &quot;[Detalhes das Fontes de Instalação](./install-sources/)&quot;">​</a></h3><p>Explicação detalhada das três fontes de instalação: repositórios GitHub, caminhos locais e repositórios Git privados. Cenários de aplicação, formatos de comando e considerações para cada método.</p><h3 id="instalacao-global-vs-local-por-projeto" tabindex="-1"><a href="./global-vs-project/">Instalação Global vs Local por Projeto</a> <a class="header-anchor" href="#instalacao-global-vs-local-por-projeto" aria-label="Permalink to &quot;[Instalação Global vs Local por Projeto](./global-vs-project/)&quot;">​</a></h3><p>Explicação das diferenças entre instalação <code>--global</code> e padrão (local por projeto), ajudando você a escolher o local de instalação adequado e compreender as regras de prioridade de busca de skills.</p><h3 id="listar-skills-instaladas" tabindex="-1"><a href="./list-skills/">Listar Skills Instaladas</a> <a class="header-anchor" href="#listar-skills-instaladas" aria-label="Permalink to &quot;[Listar Skills Instaladas](./list-skills/)&quot;">​</a></h3><p>Aprenda a usar o comando <code>list</code> para visualizar skills instaladas e compreenda o significado das etiquetas de localização <code>(project)</code> e <code>(global)</code>.</p><h3 id="atualizar-skills" tabindex="-1"><a href="./update-skills/">Atualizar Skills</a> <a class="header-anchor" href="#atualizar-skills" aria-label="Permalink to &quot;[Atualizar Skills](./update-skills/)&quot;">​</a></h3><p>Guia para usar o comando <code>update</code> para atualizar skills instaladas, com suporte para atualização total ou de skills específicas, mantendo as skills sincronizadas com o repositório de origem.</p><h3 id="remover-skills" tabindex="-1"><a href="./remove-skills/">Remover Skills</a> <a class="header-anchor" href="#remover-skills" aria-label="Permalink to &quot;[Remover Skills](./remove-skills/)&quot;">​</a></h3><p>Introdução a dois métodos de remoção: comando interativo <code>manage</code> e comando scriptável <code>remove</code>, ajudando você a gerenciar sua biblioteca de skills de forma eficiente.</p><h2 id="caminhos-de-aprendizado" tabindex="-1">Caminhos de Aprendizado <a class="header-anchor" href="#caminhos-de-aprendizado" aria-label="Permalink to &quot;Caminhos de Aprendizado&quot;">​</a></h2><p>Escolha o caminho de aprendizado adequado às suas necessidades:</p><h3 id="caminho-a-aprendizado-sistematico-recomendado-para-iniciantes" tabindex="-1">Caminho A: Aprendizado Sistemático (Recomendado para Iniciantes) <a class="header-anchor" href="#caminho-a-aprendizado-sistematico-recomendado-para-iniciantes" aria-label="Permalink to &quot;Caminho A: Aprendizado Sistemático (Recomendado para Iniciantes)&quot;">​</a></h3><p>Estude todo o conteúdo em ordem para construir um conhecimento completo:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Detalhes dos Comandos → Fontes de Instalação → Global vs Projeto → Listar Skills → Atualizar Skills → Remover Skills</span></span></code></pre></div><h3 id="caminho-b-consulta-sob-demanda" tabindex="-1">Caminho B: Consulta sob Demanda <a class="header-anchor" href="#caminho-b-consulta-sob-demanda" aria-label="Permalink to &quot;Caminho B: Consulta sob Demanda&quot;">​</a></h3><p>Acesse diretamente de acordo com sua tarefa atual:</p><table tabindex="0"><thead><tr><th>O que você quer fazer</th><th>Leia isto</th></tr></thead><tbody><tr><td>Consultar a sintaxe de um comando</td><td><a href="./cli-commands/">Detalhes dos Comandos</a></td></tr><tr><td>Instalar skill de repositório privado</td><td><a href="./install-sources/">Detalhes das Fontes de Instalação</a></td></tr><tr><td>Decidir entre instalação global ou por projeto</td><td><a href="./global-vs-project/">Global vs Projeto</a></td></tr><tr><td>Ver quais skills estão instaladas</td><td><a href="./list-skills/">Listar Skills Instaladas</a></td></tr><tr><td>Atualizar skills para a versão mais recente</td><td><a href="./update-skills/">Atualizar Skills</a></td></tr><tr><td>Limpar skills não utilizadas</td><td><a href="./remove-skills/">Remover Skills</a></td></tr></tbody></table><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após concluir este capítulo, você terá dominado as skills de uso diário do OpenSkills. Em seguida, você pode:</p><ul><li><strong><a href="./../advanced/">Funcionalidades Avançadas</a></strong>: Aprenda modos avançados como o modo Universal, caminhos de saída personalizados, links simbólicos e criação de skills personalizadas</li><li><strong><a href="./../faq/">Perguntas Frequentes</a></strong>: Consulte o FAQ e guias de solução de problemas quando encontrar dificuldades</li></ul>',29)])])}const h=e(l,[["render",t]]);export{u as __pageData,h as default};
